import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repositoryRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const generatedType = path.join(
  repositoryRoot,
  "packages",
  "contracts",
  "generated",
  "api.d.ts",
);
const generatorHeader = `/**
 * This file was auto-generated by openapi-typescript.
 * Do not make direct changes to the file.
 */`;
const repositoryHeader = `/**
 * Generated from packages/contracts/openapi/openapi.yaml.
 * Regenerate with: pnpm contracts:generate
 * Do not make direct changes to this file.
 */`;

const content = await readFile(generatedType, "utf8");
if (!content.startsWith(generatorHeader)) {
  throw new Error("The generated API type header was not recognized.");
}

await writeFile(
  generatedType,
  content.replace(generatorHeader, repositoryHeader),
  "utf8",
);
